package in.fundamentals;

public class Literals2 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		//local variables
		//Decimal Literals base10	range:0-9
		int a=123;
		int b=230;
		
		//octaliterals
		int a1=0123; //1*8square+2*8+3*8power0     range:0-7
		int b1=0456;
		//int c=0589;
		
		
		//Hexadecimals 0X range:0-9,A-F
		int a3=0X123;
		int a4=0X456;
		
		System.out.println(a);
		System.out.println(b);
		System.out.println(a1);

		System.out.println(b1);
		System.out.println(a3);

		System.out.println(a4);

		//System.out.println(c);//out of range for octal 0-7





	}

}
